  animation: flyRight 0.5s var(--ease-smooth) forwards;
}
.vocab-card.fly-up {
  animation: flyUp 0.5s var(--ease-smooth) forwards;
}

@keyframes flyLeft {
  to { transform: translateX(-150%) rotate(-30deg); opacity: 0; }
}
@keyframes flyRight {
  to { transform: translateX(150%) rotate(30deg); opacity: 0; }
}
@keyframes flyUp {
  to { transform: translateY(-150%) scale(0.8); opacity: 0; }
}

/* Bottom Sheet (Drawer) */
.bottom-sheet {
  transform: translateY(100%);
  transition: transform 0.4s var(--ease-spring);
}
.bottom-sheet.open {
  transform: translateY(0);
}

/* Staggered Fade In for Lists */
.stagger-item {
  opacity: 0;
  transform: translateY(20px);
  animation: fadeInUp 0.6s var(--ease-smooth) forwards;
}
.stagger-item:nth-child(1) { animation-delay: 0.1s; }
.stagger-item:nth-child(2) { animation-delay: 0.2s; }
.stagger-item:nth-child(3) { animation-delay: 0.3s; }
.stagger-item:nth-child(4) { animation-delay: 0.4s; }

/* Pulse for active recording/listening */
@keyframes subtlePulse {
  0%, 100% { opacity: 1; transform: scale(1); }
  50% { opacity: 0.8; transform: scale(1.05); }
}
.pulse-soft { animation: subtlePulse 2s infinite ease-in-out; }
